#include<bits/stdc++.h>
using namespace std;
int u[100005][25];
int d[100005][25];
int n,q;
int main(){
    cin>>n>>q;
    u[1][0]=1;

    for(int i=2;i<=n;i++){
        int x;
        cin>>x;
        if(d[x][0]==0) d[x][0]=i;
        u[i][0]=x;
    }
    for(int i=1;i<=n;i++){
        if(d[i][0]==0) d[i][0]=i;
    }
    for(int i=1;i<=20;i++){
        for(int j=1;j<=n;j++){
            u[j][i]=u[u[j][i-1]][i-1];
            d[j][i]=d[d[j][i-1]][i-1];
        }
    }
    while(q--){
        int s,k;
        cin>>s>>k;
        for(int i=1;i<=k;i++){
            int x;
            cin>>x;

            if(x>0){
                for(int i=0; i<=20; i++) {
                    if(x >> i & 1) s = u[s][i];
                }
            }
            if(x<0){
                x=-x;
                for(int i=0; i<=20; i++) {
                    if(x >> i & 1) s = d[s][i];
                }

            }
        }
        cout<<s<<"\n";
    }
    return 0;
}
